/**
 * BACResolutionPreview.tsx
 *
 * Exports:
 *  - BACResolutionData  (TypeScript interface)
 *  - buildBACResolutionHTML(data)  → HTML string ready for WebView / expo-print
 *
 * Logos are embedded as base64 so the document renders offline without
 * any preloadLogos() call. Drop this file into (components)/ and import
 * from BACResolutionPreviewModal.
 */

// ─── Logos (base64 PNGs) ──────────────────────────────────────────────────────

const DAR_LOGO_B64 = "";
const BP_LOGO_B64  = "";

// ─── Data shape ───────────────────────────────────────────────────────────────

export interface BACResolutionData {
  /** e.g. "2025-001" */
  resolutionNo: string;
  /** e.g. "January 15, 2025" */
  resolvedDate: string;
  /** e.g. "Camarines Sur Provincial Office" */
  provincialOffice: string;
  /** Full address line */
  officeAddress?: string;
  /** Name of the project / procurement */
  projectTitle: string;
  /** ABC (Approved Budget for the Contract) formatted string */
  approvedBudget: string;
  /** Mode of procurement, e.g. "Shopping" */
  procurementMode: string;
  /** Fund source, e.g. "General Appropriations Act (GAA)" */
  fundSource?: string;
  /** PR No. */
  prNo?: string;
  /** PR Date */
  prDate?: string;
  /** Array of BAC member names */
  bacMembers: Array<{
    name: string;
    designation: string;
    role: string;          // e.g. "Chairperson", "Member", "Member - TWG"
  }>;
  /** Name of the recommending officer */
  recommendedBy?: string;
  recommendedByTitle?: string;
  /** Approving authority */
  approvedBy?: string;
  approvedByTitle?: string;
  /** Awarded supplier / winning bidder */
  awardedTo?: string;
  /** Awarded amount formatted string */
  awardedAmount?: string;
  /** Short narrative body (may contain \n line breaks) */
  resolutionBody?: string;
}

// ─── HTML builder ─────────────────────────────────────────────────────────────

export function buildBACResolutionHTML(
  d: BACResolutionData,
  opts?: { template?: boolean },
): string {
  const template = !!opts?.template;
  const officeAddress =
    (template ? "" : d.officeAddress) ??
    "2/F HL BLDG., CARNATION ST., BRGY. TRIANGULO, NAGA CITY";

  const body =
    template
      ? `The Bids and Awards Committee (BAC) of the ________________________, after ` +
        `having deliberated on the matter, hereby resolves to recommend the award ` +
        `of the contract for the procurement of ________________________ through ` +
        `________________________ with an Approved Budget for the Contract (ABC) of ` +
        `________________________, which is within the ABC and compliant with the provisions of RA 9184 ` +
        `and its Revised IRR.`
      : d.resolutionBody ??
        `The Bids and Awards Committee (BAC) of the ${d.provincialOffice}, after ` +
          `having deliberated on the matter, hereby resolves to recommend the award ` +
          `of the contract for the procurement of ${d.projectTitle} through ` +
          `${d.procurementMode} with an Approved Budget for the Contract (ABC) of ` +
          `${d.approvedBudget}${
            d.awardedTo
              ? ` to ${d.awardedTo} in the amount of ${d.awardedAmount ?? d.approvedBudget}`
              : ""
          }, which is within the ABC and compliant with the provisions of RA 9184 ` +
          `and its Revised IRR.`;

  const members = template
    ? Array.from({ length: 6 }).map(() => ({
        name: "",
        designation: "",
        role: "",
      }))
    : d.bacMembers;

  const memberRows = members
    .map(
      (m) => `
      <tr>
        <td style="padding:3px 8px; border:1px solid #ccc;">${m.name}</td>
        <td style="padding:3px 8px; border:1px solid #ccc;">${m.designation}</td>
        <td style="padding:3px 8px; border:1px solid #ccc;">${m.role}</td>
      </tr>`
    )
    .join("");

  return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1"/>
<title>BAC Resolution No. ${template ? "" : d.resolutionNo}</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    font-family: "Times New Roman", Times, serif;
    font-size: 11pt;
    color: #000;
    background: #fff;
    padding: 14mm 18mm 18mm 18mm;
    line-height: 1.5;
  }
  table { border-collapse: collapse; width: 100%; }
  .hr { border: none; border-top: 1.5px solid #000; margin: 6px 0 14px; }
  .center { text-align: center; }
  .bold { font-weight: bold; }
  .title {
    text-align: center;
    font-size: 13pt;
    font-weight: bold;
    letter-spacing: 0.4px;
    margin: 10px 0 4px;
    text-transform: uppercase;
  }
  .subtitle {
    text-align: center;
    font-size: 11pt;
    margin-bottom: 2px;
  }
  .res-no {
    text-align: center;
    font-size: 11pt;
    margin-bottom: 16px;
  }
  .section-label {
    font-weight: bold;
    font-size: 10pt;
    margin: 14px 0 4px;
    text-transform: uppercase;
    letter-spacing: 0.3px;
  }
  .body-text {
    text-align: justify;
    line-height: 1.8;
    margin-bottom: 12px;
    text-indent: 36pt;
  }
  .sig-block {
    width: 46%;
    text-align: center;
    display: inline-block;
    vertical-align: top;
  }
  .sig-line {
    border-top: 1px solid #000;
    margin-top: 28px;
    padding-top: 3px;
    font-weight: bold;
    font-size: 10.5pt;
  }
  .sig-sub {
    font-size: 9.5pt;
    color: #444;
  }
  .members-table td {
    font-size: 10pt;
  }
  .footer-ref {
    margin-top: 28px;
    font-size: 9pt;
    color: #555;
    text-align: right;
  }
</style>
</head>
<body>

<!-- ── Letterhead ── -->
<table style="margin-bottom:4px;">
  <colgroup>
    <col style="width:13%"/>
    <col style="width:74%"/>
    <col style="width:13%"/>
  </colgroup>
  <tr>
    <td style="text-align:center; vertical-align:middle; padding:4px 6px 4px 0;">
      <img src="data:image/png;base64,${DAR_LOGO_B64}"
           style="height:62px; width:auto; display:block; margin:0 auto;"/>
    </td>
    <td style="vertical-align:middle; text-align:center; padding:2px 4px;">
      <div style="font-size:10pt; line-height:1.4;">Republic of the Philippines</div>
      <div style="font-size:13pt; font-weight:bold; line-height:1.3;">DEPARTMENT OF AGRARIAN REFORM</div>
      <div style="font-size:10pt; line-height:1.4;">${template ? "" : d.provincialOffice}</div>
      <div style="font-size:9.5pt; line-height:1.4;">${officeAddress}</div>
    </td>
    <td style="text-align:center; vertical-align:middle; padding:4px 0 4px 6px;">
      <img src="data:image/png;base64,${BP_LOGO_B64}"
           style="height:62px; width:auto; display:block; margin:0 auto;"/>
    </td>
  </tr>
</table>

<hr class="hr"/>

<!-- ── Document title ── -->
<div class="title">BAC Resolution</div>
<div class="subtitle">Bids and Awards Committee</div>
<div class="res-no">
  <span class="bold">Resolution No. ${template ? "" : d.resolutionNo}</span>
  &nbsp;&nbsp;|&nbsp;&nbsp;
  ${template ? "" : d.resolvedDate}
</div>

<!-- ── Subject / project info strip ── -->
<table style="margin-bottom:14px; font-size:10pt;">
  <tr>
    <td style="width:22%; font-weight:bold; padding:2px 6px 2px 0; vertical-align:top;">Subject&nbsp;:</td>
    <td style="padding:2px 0; vertical-align:top;">${template ? "" : d.projectTitle}</td>
  </tr>
  <tr>
    <td style="font-weight:bold; padding:2px 6px 2px 0; vertical-align:top;">Mode&nbsp;:</td>
    <td style="padding:2px 0;">${template ? "" : d.procurementMode}</td>
  </tr>
  <tr>
    <td style="font-weight:bold; padding:2px 6px 2px 0; vertical-align:top;">ABC&nbsp;:</td>
    <td style="padding:2px 0;">${template ? "" : d.approvedBudget}</td>
  </tr>
  ${
    d.prNo
      ? `<tr>
    <td style="font-weight:bold; padding:2px 6px 2px 0; vertical-align:top;">PR No.&nbsp;:</td>
    <td style="padding:2px 0;">${template ? "" : d.prNo}${!template && d.prDate ? ` &nbsp; dated ${d.prDate}` : ""}</td>
  </tr>`
      : ""
  }
  ${
    d.fundSource
      ? `<tr>
    <td style="font-weight:bold; padding:2px 6px 2px 0; vertical-align:top;">Fund&nbsp;:</td>
    <td style="padding:2px 0;">${template ? "" : d.fundSource}</td>
  </tr>`
      : ""
  }
</table>

<!-- ── Resolution body ── -->
<div class="section-label">RESOLUTION</div>
<div class="body-text">${body.replace(/\n/g, "<br/>")}</div>

<!-- ── BAC Members table ── -->
${
  d.bacMembers.length > 0
    ? `<div class="section-label">BAC Composition</div>
<table class="members-table" style="margin-bottom:18px;">
  <thead>
    <tr style="background:#f0fdf4;">
      <th style="padding:4px 8px; border:1px solid #ccc; text-align:left; font-size:9.5pt;">Name</th>
      <th style="padding:4px 8px; border:1px solid #ccc; text-align:left; font-size:9.5pt;">Designation</th>
      <th style="padding:4px 8px; border:1px solid #ccc; text-align:left; font-size:9.5pt;">Role</th>
    </tr>
  </thead>
  <tbody>${memberRows}</tbody>
</table>`
    : ""
}

<!-- ── Signature blocks ── -->
<div style="margin-top:24px;">

  ${
    d.recommendedBy
      ? `<div class="sig-block" style="float:left; margin-left:4%;">
    <div class="sig-line">${template ? "" : d.recommendedBy}</div>
    <div class="sig-sub">${d.recommendedByTitle ?? "BAC Chairperson"}</div>
    <div class="sig-sub">Recommending Approval</div>
  </div>`
      : ""
  }

  ${
    d.approvedBy
      ? `<div class="sig-block" style="float:right; margin-right:4%;">
    <div class="sig-line">${template ? "" : d.approvedBy}</div>
    <div class="sig-sub">${d.approvedByTitle ?? "Head of the Procuring Entity"}</div>
    <div class="sig-sub">Approved</div>
  </div>`
      : ""
  }

  <div style="clear:both;"></div>
</div>

<!-- ── Footer reference ── -->
<div class="footer-ref">DAR CS1-QF-BAC-001</div>

</body>
</html>`;
}
